INSERT INTO design_cases (title, theme, style, space_type, budget_level, summary, source_url) VALUES
('春节中庭美陈设计方案', '春节', '国潮新中式', '中庭', 'high', '以传统春节元素为灵感，结合现代设计手法，打造沉浸式新春体验空间。主装置采用剪纸艺术造型，搭配LED灯带和互动投影，营造喜庆祥和的节日氛围。中央设置巨型灯笼装置，四周环绕祥云图案装饰，地面铺设红色地毯引导人流。', ''),
('夏日清凉主题快闪店', '夏日清凉', '现代简约', '快闪店', 'medium', '以海洋蓝和薄荷绿为主色调，打造清凉舒适的夏日快闪空间。采用透明亚克力和冰纹玻璃材质，搭配仿真绿植和喷雾装置，营造降温效果。设置互动拍照区和产品展示区，适合年轻消费群体打卡分享。', ''),
('圣诞节橱窗装饰设计', '圣诞节', '高端奢华', '橱窗', 'premium', '采用金色和银色为主色调，搭配璀璨灯光和水晶装饰，打造奢华大气的圣诞橱窗。中央设置圣诞树装置，悬挂手工制作的装饰挂件，底部布置雪景效果。橱窗玻璃采用雪花图案贴膜，营造浪漫梦幻的节日氛围。', ''),
('科技未来主题中庭装置', '科技未来', '现代简约', '中庭', 'premium', '以未来科技为主题，打造沉浸式数字艺术装置。采用LED点阵屏和全息投影技术，呈现动态光影效果。设置互动感应装置，游客靠近时触发光影变化。整体造型采用流线型设计，展现科技感和未来感。', ''),
('秋季丰收主题美陈', '秋季丰收', '复古怀旧', '入口', 'medium', '以秋季丰收为主题，采用温暖的橙黄色调。使用麦穗、南瓜、枫叶等自然元素，搭配木质结构和麻绳装饰，营造田园气息。入口处设置丰收拱门，两侧布置农作物展示区，适合商场秋季促销活动。', ''),
('品牌周年庆主题装置', '品牌周年庆', '高端奢华', '中庭', 'premium', '为品牌十周年庆典打造的主题装置。采用品牌主色调，搭配金色元素和镜面材质，营造尊贵大气的氛围。中央设置发光数字"10"造型，四周环绕品牌历史回顾展示墙。设置互动留言区，增强顾客参与感。', ''),
('情人节主题橱窗设计', '情人节', '浪漫温馨', '橱窗', 'medium', '以浪漫爱情为主题，采用粉色和红色为主色调。布置心形装置和玫瑰装饰，搭配柔和灯光和纱幔效果。橱窗内设置情侣互动场景，营造甜蜜浪漫的氛围。适合珠宝、化妆品等品牌情人节促销。', ''),
('艺术展主题走廊布置', '艺术展', '现代简约', '走廊', 'medium', '为当代艺术展打造的走廊布置。采用黑白灰为主色调，搭配极简线条设计。墙面悬挂艺术作品，地面铺设发光灯带引导参观动线。设置休息区和导览牌，提升观展体验。', ''),
('端午节主题美陈', '端午节', '国潮新中式', '中庭', 'medium', '以端午节传统元素为主题，采用绿色和金色为主色调。布置龙舟造型装置和粽子装饰，搭配艾草和菖蒲等传统植物。设置互动体验区，顾客可以参与包粽子活动，增强节日氛围。', ''),
('冬季冰雪主题装置', '冬季冰雪', '创意互动', '广场', 'high', '以冰雪世界为主题，打造大型户外互动装置。采用冰蓝色调，搭配仿真冰雪材质和LED冰柱装饰。设置冰雪滑梯和互动投影游戏，适合亲子家庭游玩。夜间灯光效果绚丽，成为城市地标性景观。', ''),
('春季花卉主题中庭', '春季花卉', '浪漫温馨', '中庭', 'high', '以春季花卉为主题，打造花海般的中庭空间。布置巨型花朵装置和仿真绿植墙，搭配蝴蝶和蜜蜂造型装饰。采用粉色、黄色、白色为主色调，营造春意盎然的氛围。适合商场春季促销和妇女节活动。', ''),
('万圣节主题橱窗', '万圣节', '创意互动', '橱窗', 'medium', '以万圣节为主题，打造神秘有趣的橱窗设计。采用黑色和橙色为主色调，布置南瓜灯、幽灵、蝙蝠等装饰元素。设置互动机关，顾客靠近时触发动画效果。适合服装、饰品等品牌万圣节促销。', ''),
('新年倒计时装置', '新年', '高端奢华', '广场', 'premium', '为新年倒计时打造的大型户外装置。采用LED显示屏和钢结构造型，呈现动态数字倒计时。搭配烟花效果和音乐同步，营造热烈欢快的氛围。成为城市跨年活动的核心亮点。', ''),
('环保主题展览装置', '环保', '现代简约', '中庭', 'medium', '以绿色环保为主题，打造沉浸式展览装置。采用回收材料制作艺术装置，展示环保理念。设置互动体验区，顾客可以了解垃圾分类和可持续发展知识。适合购物中心环保主题活动。', ''),
('中秋节主题美陈', '中秋节', '国潮新中式', '中庭', 'high', '以中秋节传统元素为主题，采用深蓝色和金色为主色调。布置巨型月亮装置和灯笼装饰，搭配玉兔和桂花等传统元素。设置赏月区和互动游戏区，顾客可以参与猜灯谜活动，增强节日氛围。', ''),
('音乐节主题快闪店', '音乐节', '创意互动', '快闪店', 'medium', '以音乐节为主题，打造充满活力的快闪空间。采用霓虹灯和涂鸦艺术风格，搭配音响设备和舞台装置。设置DJ台和互动拍照区，适合年轻人打卡和品牌推广活动。', ''),
('母亲节主题橱窗', '母亲节', '浪漫温馨', '橱窗', 'medium', '以感恩母爱为主题，采用粉色和紫色为主色调。布置鲜花和礼物装饰，搭配温馨灯光效果。橱窗内设置母子互动场景，传达感恩和爱的主题。适合珠宝、美妆等品牌母亲节促销。', ''),
('电竞主题展览装置', '电竞', '现代简约', '中庭', 'premium', '以电竞游戏为主题，打造沉浸式展览空间。采用RGB灯光和科技感设计，布置游戏角色雕塑和互动体验区。设置电竞比赛舞台和观赛区，吸引年轻消费群体。适合游戏品牌推广和电竞活动。', ''),
('国庆节主题美陈', '国庆节', '国潮新中式', '入口', 'high', '以国庆为主题，采用红色和金色为主色调。布置国旗元素和天安门造型装饰，搭配和平鸽和鲜花点缀。入口处设置国庆拱门，营造庄重热烈的节日氛围。适合商场国庆促销活动。', ''),
('儿童节主题中庭', '儿童节', '创意互动', '中庭', 'medium', '以儿童为主题，打造充满童趣的中庭空间。采用彩虹色和卡通造型，布置游乐设施和互动游戏区。设置亲子互动区和表演舞台，适合儿童节期间举办各类亲子活动。', ''),
('双十一促销主题装置', '双十一', '创意互动', '中庭', 'high', '以双十一购物节为主题，打造促销氛围浓厚的中庭装置。采用红色和橙色为主色调，布置巨型购物袋和折扣标签装饰。设置互动抽奖区和促销信息展示屏，吸引顾客参与购物活动。', ''),
('冬季暖心主题美陈', '冬季暖心', '现代简约', '入口', 'medium', '以冬季暖心为主题，采用暖色调和柔软材质。布置毛绒装饰和热饮元素，搭配温暖灯光效果。入口处设置欢迎装置，让顾客感受到温馨舒适的氛围。适合商场冬季促销活动。', ''),
('毕业季主题展览', '毕业季', '浪漫温馨', '走廊', 'medium', '以毕业季为主题，打造青春回忆展览空间。布置书本、学士帽、毕业证书等元素，搭配照片展示墙。设置留言区和拍照区，让毕业生留下美好回忆。适合购物中心毕业季活动。', ''),
('世界杯主题装置', '世界杯', '创意互动', '广场', 'high', '以世界杯足球赛为主题，打造大型户外观赛装置。布置巨型足球和各国国旗装饰，搭配LED显示屏直播比赛。设置互动游戏区和球迷休息区，成为球迷聚集地。', ''),
('奢侈品品牌快闪店', '品牌展示', '高端奢华', '快闪店', 'premium', '为奢侈品品牌打造的快闪店空间。采用品牌经典元素和高级材质，搭配低调奢华的灯光效果。设置产品展示区和VIP体验区，提供专属服务。适合高端品牌限时推广活动。');
